```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
    // Open the text file for reading
    ifstream file("textfile.txt");
    if (!file) {
        cout << "Error opening file." << endl;
        return 1;
    }

    // Initialize variables
    int wordCount = 0;
    string word;

    // Read each line of the file
    string line;
    while (getline(file, line)) {
        // Count the occurrences of the word
        size_t found = line.find(word);
        if (found != string::npos) {
            wordCount++;
        }
    }

    // Print the result
    cout << "The word '" << word << "' occurs " << wordCount << " times in the file." << endl;

    // Close the file
    file.close();

    return 0;
}
```

